	//        "timeInForce": "GTC",
	//        "postOnly": false,
	//        "hidden": false,
	//        "iceberg": false,
	//        "visibleSize": "0",
	//        "cancelAfter": 0,
	//        "channel": "API",
	//        "clientOid": "d602d73f-5424-4751-bef0-8debce8f0a82",
	//        "remark": null,
